<?php
namespace App\Domain\Characters\Actions;
use App\Domain\Characters\Accounts\CharacterAccountLimit;use App\Domain\Characters\Accounts\CharacterNameNormalizer;use App\Domain\Characters\Accounts\ReservedCharacterNames;use App\Domain\Characters\CharacterStatus;use App\Domain\Characters\Templates\CharacterTemplatePresentationGender;use App\Domain\Characters\Templates\CharacterTemplateValidator;use App\Domain\Inventory\Capacity\InventoryCapacityLimits;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Character;use App\Models\CharacterClass;use App\Models\CharacterTemplate;use App\Models\User;use Illuminate\Database\QueryException;use Illuminate\Support\Facades\DB;use Illuminate\Validation\ValidationException;
final class CreateCharacterAction{private $templates;private $names;private $reserved;public function __construct(CharacterTemplateValidator $templates,CharacterNameNormalizer $names,ReservedCharacterNames $reserved){$this->templates=$templates;$this->names=$names;$this->reserved=$reserved;}public function execute(User $user,$name,$templateId){try{return DB::transaction(function()use($user,$name,$templateId){$lockedUser=User::whereKey($user->id)->lockForUpdate()->firstOrFail();if($lockedUser->characters()->count()>=CharacterAccountLimit::MAX_CHARACTERS)throw ValidationException::withMessages(['name'=>'Has alcanzado el máximo de personajes de esta cuenta.']);$visible=$this->names->visible($name);$normalized=$this->names->normalized($visible);if(mb_strlen($visible,'UTF-8')<3||mb_strlen($visible,'UTF-8')>20||!preg_match('/^(?![0-9 ]+$)[\pL\pN]+(?: [\pL\pN]+)*$/u',$visible))throw ValidationException::withMessages(['name'=>'El nombre no cumple las reglas permitidas.']);if($this->reserved->contains($normalized))throw ValidationException::withMessages(['name'=>'Ese nombre está reservado.']);$template=CharacterTemplate::with(['characterClass','mediaAssets'])->whereKey($templateId)->lockForUpdate()->first();if(!$template||$template->status!==CatalogStatus::ACTIVE)throw ValidationException::withMessages(['template_id'=>'La plantilla seleccionada no está disponible.']);$class=CharacterClass::whereKey($template->character_class_id)->lockForUpdate()->first();if(!$class||$class->status!==CatalogStatus::ACTIVE)throw ValidationException::withMessages(['template_id'=>'La clase de la plantilla no está disponible.']);if(!in_array($template->presentation_gender,CharacterTemplatePresentationGender::all(),true))throw ValidationException::withMessages(['template_id'=>'La presentación de la plantilla no es válida.']);$template->setRelation('characterClass',$class);try{$this->templates->validate($template,true);}catch(\InvalidArgumentException $e){throw ValidationException::withMessages(['template_id'=>$e->getMessage()]);}$character=new Character();$character->name=$visible;$character->normalized_name=$normalized;$character->character_class_id=$class->id;$character->character_template_id=$template->id;$character->level=1;$character->experience=0;$character->base_max_health=(int)$template->base_max_health;$character->current_health=(int)$template->base_max_health;$character->base_attack=(int)$template->base_attack;$character->base_defense=(int)$template->base_defense;$character->base_accuracy=(int)$template->base_accuracy;$character->base_evasion=(int)$template->base_evasion;$character->base_critical_rate=(string)$template->base_critical_rate;$character->status=CharacterStatus::ACTIVE;$character->base_inventory_slots=InventoryCapacityLimits::DEFAULT_BASE_SLOTS;$lockedUser->characters()->save($character);$lockedUser->active_character_id=$character->id;$lockedUser->save();$user->active_character_id=$character->id;return$character;},3);}catch(QueryException $e){if((string)$e->getCode()==='23000')throw ValidationException::withMessages(['name'=>'Ese nombre ya está siendo utilizado por otro personaje.']);throw$e;}}}
